form:Form.form:Scripts:
		function ValidaGrilla (pobjButton) {

	var bolResult = true;
	var strMen = "";
	var objGrid = Ctrl("grdVariables");
	var x;
	var strTipo;
	var strValor;
	var objTextBox;

	var TotalRows = objGrid.TotalRowsCount(); 

  for (x = 0; x < TotalRows ; x++) 
  {           

  	//La variable esta dada de Alta
  	strVariable = objGrid.GetCellXValue("cboGridVariable", x);
  	if (strVariable!="")
  	{
			strValor = objGrid.GetCellXValue("txtGridValor", x);
			if (strValor=="")
			{
				alert("El valor es Requerido.");
				return false;
			}

			strFecha = objGrid.GetCellXValue("dteGridPeriodo", x);
			if (strFecha=="")
			{
				alert("El periodo es Requerido.");
				return false;
			}             

			if (!isDouble(strValor))
			{
				alert("Formato inválido de número decimal.");
				return false;
			}
  	}
  }



	return bolResult;
}
